// Parentクラスの定義
class Parent {
    // 変数の宣言と初期化
    String name = "Parent";
    // greetメソッドの定義
    String greet() { return "Hello from Parent"; }
}
// Childクラスの定義
class Child extends Parent {
    String name = "Child";
    // greetメソッドの定義
    String greet() { return "Hello from Child"; }
}

Parent obj = new Child();
System.out.println(obj.greet());  // "Hello from Child"（動的バインディング）
System.out.println(obj.name);     // "Parent"（フィールドは静的バインディング）

