// Aクラスの定義
class A {
    A() { System.out.print("A"); }
    // execメソッドの定義
    void exec() throws Exception {
        System.out.print("a");
        // 例外を投げる
        throw new Exception();
    }
}
// Bクラスの定義
class B extends A {
    B() { System.out.print("B"); }
    // execメソッドの定義
    void exec() throws Exception {
        System.out.print("b");
        super.exec();
    }
}
// new B().exec() → 出力: "ABba" + Exception発生

// Shapeクラスの定義
class Shape {
    // areaメソッドの定義
    double area() { return 0; }
    // toStringメソッドの定義
    public String toString() { return "Shape:" + area(); }
}
// Circleクラスの定義
class Circle extends Shape {
    double r;
    Circle(double r) { this.r = r; }
    double area() { return 3.14 * r * r; }
}
// Mainクラスの定義
public class Main {
    public static void main(String[] args) {
        Shape s = new Circle(5);
        System.out.println(s);  // "Shape:78.5"（toStringがarea()を呼び、動的バインディングでCircleのareaが実行）
    }
}

